fn factorial(n: i32) -> Result<u128, &'static str> {
    if n < 0 {
        return Err("El número debe ser no negativo");
    }
    if n == 0 {
        return Ok(1);
    }

    factorial(n - 1).map(|res| res * n as u128)
}

fn main() {
    let test_values = [5, 0, -3];

    for &val in &test_values {
        match factorial(val) {
            Ok(result) => println!("El factorial de {} es {}", val, result),
            Err(e) => println!("Error para {}: {}", val, e),
        }
    }
}
