/**
 * Realiza una solicitud GET con reintentos automáticos.
 * 
 * @param {string} url - La URL de la API.
 * @param {object} options - Opciones adicionales para fetch.
 * @param {number} maxRetries - Número máximo de intentos.
 * @returns {Promise<any>} - Promesa que resuelve con el JSON de la respuesta.
 */
const fetchDataWithRetry = async (url, options = {}, maxRetries = 3) => {
  let lastError;

  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const response = await fetch(url, {
        method: 'GET',
        ...options,
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      lastError = error;
      console.error(`Intento ${attempt} fallido: ${error.message}`);

      if (attempt < maxRetries) {
        // Espera exponencialmente antes de reintentar (1s, 2s...)
        const delay = attempt * 1000;
        await new Promise((resolve) => setTimeout(resolve, delay));
      }
    }
  }

  throw new Error(`Se agotaron los reintentos. Último error: ${lastError.message}`);
};

// Ejemplo de uso:
const API_URL = 'https://jsonplaceholder.typicode.com/posts/1';

fetchDataWithRetry(API_URL)
  .then((data) => console.log('Datos recibidos:', data))
  .catch((err) => console.error('Error final:', err.message));
